function perpusLegacyTableExists(mysqli $db,string $table):bool{
 $stmt=$db->prepare('SELECT 1 FROM information_schema.TABLES WHERE TABLE_SCHEMA=DATABASE() AND TABLE_NAME=? LIMIT 1');$stmt->bind_param('s',$table);$stmt->execute();$ok=(bool)$stmt->get_result()->fetch_row();$stmt->close();return $ok;
}
function perpusLegacyColumnExists(mysqli $db,string $table,string $column):bool{
 $stmt=$db->prepare('SELECT 1 FROM information_schema.COLUMNS WHERE TABLE_SCHEMA=DATABASE() AND TABLE_NAME=? AND COLUMN_NAME=? LIMIT 1');$stmt->bind_param('ss',$table,$column);$stmt->execute();$ok=(bool)$stmt->get_result()->fetch_row();$stmt->close();return $ok;
}
function perpusLegacyCodeWhere(mysqli $db,string $table,string $code,string $alias=''):string{
 if($code===''||!perpusLegacyColumnExists($db,$table,'kodeapp'))return '';
 $column=($alias!==''?'`'.$alias.'`.':'').'`kodeapp`';
 return ' WHERE '.$column."='".$db->real_escape_string($code)."'";
}
function perpusLegacyDate($value):?string{$v=trim((string)$value);if($v===''||$v==='0000-00-00')return null;$t=strtotime($v);return $t?date('Y-m-d',$t):null;}
function perpusFindStudent(mysqli $conn,string $idAnggota,string $nis,string $name,?string $dob):int{
 foreach(array_unique(array_filter([$nis,$idAnggota])) as $key){$stmt=$conn->prepare("SELECT ps.id FROM pendaftaran_siswa ps LEFT JOIN kartu_rfid kr ON kr.pemilik_tipe='siswa' AND kr.pemilik_id=ps.id WHERE ps.nisn=? OR ps.nipd=? OR kr.uid=? OR ps.rfid_uid=? LIMIT 1");$stmt->bind_param('ssss',$key,$key,$key,$key);$stmt->execute();$id=(int)($stmt->get_result()->fetch_assoc()['id']??0);$stmt->close();if($id>0)return $id;}
 if($name!==''&&$dob){$stmt=$conn->prepare('SELECT id FROM pendaftaran_siswa WHERE UPPER(TRIM(nama_lengkap))=UPPER(TRIM(?)) AND tanggal_lahir=? LIMIT 1');$stmt->bind_param('ss',$name,$dob);$stmt->execute();$id=(int)($stmt->get_result()->fetch_assoc()['id']??0);$stmt->close();if($id>0)return $id;}return 0;
}
function perpusFindEmployee(mysqli $conn,string $idAnggota,string $nis,string $name,?string $dob):int{
 foreach(array_unique(array_filter([$nis,$idAnggota])) as $key){$stmt=$conn->prepare("SELECT p.pegawai_id FROM pegawai p LEFT JOIN kartu_rfid kr ON kr.pemilik_tipe='pegawai' AND kr.pemilik_id=p.pegawai_id WHERE p.nip=? OR kr.uid=? OR p.rfid=? LIMIT 1");$stmt->bind_param('sss',$key,$key,$key);$stmt->execute();$id=(int)($stmt->get_result()->fetch_assoc()['pegawai_id']??0);$stmt->close();if($id>0)return $id;}
 if($name!==''&&$dob){$stmt=$conn->prepare('SELECT pegawai_id FROM pegawai WHERE UPPER(TRIM(nama_lengkap))=UPPER(TRIM(?)) AND tanggal_lahir=? LIMIT 1');$stmt->bind_param('ss',$name,$dob);$stmt->execute();$id=(int)($stmt->get_result()->fetch_assoc()['pegawai_id']??0);$stmt->close();if($id>0)return $id;}return 0;
}
function perpusSafeMemberNumber(mysqli $conn,string $preferred,int $legacyId):string{
 $base=trim($preferred)!==''?trim($preferred):'LEGACY-'.$legacyId;$candidate=$base;$n=0;while(true){$stmt=$conn->prepare('SELECT id FROM perpus_anggota WHERE nomor_anggota=? LIMIT 1');$stmt->bind_param('s',$candidate);$stmt->execute();$exists=$stmt->get_result()->fetch_assoc();$stmt->close();if(!$exists)return $candidate;$n++;$candidate=$base.'-L'.($legacyId?:$n).($n>1?'-'.$n:'');}
}

