    if($existingId>0){$stmt=$conn->prepare('UPDATE perpus_anggota SET legacy_id_anggota=?,legacy_nis=?,legacy_nama=?,legacy_kelas=?,legacy_jurusan=?,legacy_tanggal_lahir=?,tipe_member_id=COALESCE(NULLIF(tipe_member_id,0),?),status_keanggotaan=IF(pemilik_tipe=\'legacy\',\'perlu_verifikasi\',status_keanggotaan) WHERE id=?');$stmt->bind_param('ssssssii',$oldId,$nis,$name,$kelas,$jurusan,$dob,$typeId,$existingId);$stmt->execute();$stmt->close();$newMember=$existingId;}else{$nullableOwner=$ownerId>0?$ownerId:null;$stmt=$conn->prepare('INSERT INTO perpus_anggota (pemilik_tipe,pemilik_id,nomor_anggota,tipe_member_id,status_keanggotaan,tanggal_daftar,legacy_id_anggota,legacy_nis,legacy_nama,legacy_kelas,legacy_jurusan,legacy_tanggal_lahir) VALUES (?,?,?,?,?,?,?,?,?,?,?,?)');$joined=perpusLegacyDate($r['D_CREATED']??null);$stmt->bind_param('sisissssssss',$ownerType,$nullableOwner,$number,$typeId,$status,$joined,$oldId,$nis,$name,$kelas,$jurusan,$dob);$stmt->execute();$newMember=(int)$conn->insert_id;$stmt->close();}
    if($oldId!=='')$memberMap[$oldId]=$newMember;if($nis!=='')$memberMap['nis:'.$nis]=$newMember;if($ownerId>0)$summary['anggota_matched']++;else$summary['anggota_unmatched']++;
  }}

  // Peminjaman dan detail historis.
  $loanMap=[];$res=$legacy->query('SELECT * FROM peminjaman'.perpusLegacyCodeWhere($legacy,'peminjaman',$sourceCode).' ORDER BY id');$stmt=$conn->prepare("INSERT INTO perpus_peminjaman (legacy_id_pinjam,anggota_id,tanggal_pinjam,jumlah_item,status) VALUES (?,?,?,?,?) ON DUPLICATE KEY UPDATE anggota_id=VALUES(anggota_id),tanggal_pinjam=VALUES(tanggal_pinjam),jumlah_item=VALUES(jumlah_item),status=VALUES(status),id=LAST_INSERT_ID(id)");while($res&&($r=$res->fetch_assoc())){$oldLoan=(string)$r['ID_PINJAM'];$oldMember=trim((string)$r['ID_ANGGOTA']);$memberId=(int)($memberMap[$oldMember]??0);if($memberId<=0){$legacyMemberKey=$oldMember!==''?$oldMember:'LOAN-'.$oldLoan;$stmtM=$conn->prepare("SELECT id,nomor_anggota FROM perpus_anggota WHERE pemilik_tipe='legacy' AND legacy_id_anggota=? LIMIT 1");$stmtM->bind_param('s',$legacyMemberKey);$stmtM->execute();$existingLegacy=$stmtM->get_result()->fetch_assoc();$stmtM->close();if($existingLegacy){$memberId=(int)$existingLegacy['id'];}else{$number=perpusSafeMemberNumber($conn,$oldMember!==''?$oldMember:$legacyMemberKey,0);$stmtM=$conn->prepare("INSERT INTO perpus_anggota (pemilik_tipe,nomor_anggota,status_keanggotaan,legacy_id_anggota,legacy_nama) VALUES ('legacy',?,'perlu_verifikasi',?,'Anggota transaksi lama')");$stmtM->bind_param('ss',$number,$legacyMemberKey);$stmtM->execute();$memberId=(int)$conn->insert_id;$stmtM->close();}if($oldMember!=='')$memberMap[$oldMember]=$memberId;}$date=perpusLegacyDate($r['TGL_PINJAM'])?:date('Y-m-d');$count=(int)$r['JML_BUKU'];$statusLegacy=mb_strtolower((string)$r['STATS']);$status=str_contains($statusLegacy,'sudah')?'selesai':'aktif';$stmt->bind_param('sisis',$oldLoan,$memberId,$date,$count,$status);$stmt->execute();$loanMap[$oldLoan]=(int)$conn->insert_id;$summary['peminjaman']++;}$stmt->close();
  $res=$legacy->query('SELECT * FROM detail_pinjam'.perpusLegacyCodeWhere($legacy,'detail_pinjam',$sourceCode).' ORDER BY ID_DIPINJAM');$stmt=$conn->prepare("INSERT INTO perpus_peminjaman_detail (legacy_id_detail,peminjaman_id,buku_id,eksemplar_id,kode_resi,tanggal_jatuh_tempo,denda_awal,denda,status,tanggal_kembali) VALUES (?,?,?,?,?,?,?,?,?,?) ON DUPLICATE KEY UPDATE peminjaman_id=VALUES(peminjaman_id),buku_id=VALUES(buku_id),eksemplar_id=VALUES(eksemplar_id),kode_resi=VALUES(kode_resi),tanggal_jatuh_tempo=VALUES(tanggal_jatuh_tempo),denda_awal=VALUES(denda_awal),denda=VALUES(denda),status=VALUES(status),tanggal_kembali=VALUES(tanggal_kembali)");while($res&&($r=$res->fetch_assoc())){$legacyDetail=(int)$r['ID_DIPINJAM'];$loanId=(int)($loanMap[(string)$r['ID_PINJAM']]??0);$oldBook=(int)$r['ID_BUKU'];$bookId=(int)($bookMap[$oldBook]??0);if($loanId<=0)continue;$resi=trim((string)$r['resi']);$barcode=(string)($bookBase[$oldBook]??'').$resi;$copyId=0;if($bookId>0&&$barcode!==''){$stmtC=$conn->prepare('SELECT id FROM perpus_buku_eksemplar WHERE barcode=? LIMIT 1');$stmtC->bind_param('s',$barcode);$stmtC->execute();$copyId=(int)($stmtC->get_result()->fetch_assoc()['id']??0);$stmtC->close();}if($copyId<=0&&$bookId>0){$barcode=$barcode!==''?$barcode:'LEGACY-'.$oldBook.'-'.$resi;$stmtC=$conn->prepare("INSERT IGNORE INTO perpus_buku_eksemplar (buku_id,barcode,status,catatan) VALUES (?,?,'tersedia','Dibentuk dari transaksi lama')");$stmtC->bind_param('is',$bookId,$barcode);$stmtC->execute();$copyId=(int)$conn->insert_id;$stmtC->close();if($copyId<=0){$stmtC=$conn->prepare('SELECT id FROM perpus_buku_eksemplar WHERE barcode=? LIMIT 1');$stmtC->bind_param('s',$barcode);$stmtC->execute();$copyId=(int)($stmtC->get_result()->fetch_assoc()['id']??0);$stmtC->close();}}$due=perpusLegacyDate($r['TGL_KEMBALI']);$fineInitial=(float)($r['denda_awal']??0);$fine=(float)($r['DENDA']??0);$statusLegacy=mb_strtolower((string)$r['STATUS']);$status=str_contains($statusLegacy,'belum')?'dipinjam':'kembali';$returned=$status==='kembali'?($due?($due.' 00:00:00'):date('Y-m-d H:i:s')):null;$stmt->bind_param('iiiissddss',$legacyDetail,$loanId,$bookId,$copyId,$resi,$due,$fineInitial,$fine,$status,$returned);$stmt->execute();$summary['detail_pinjam']++;}$stmt->close();
  $conn->query("UPDATE perpus_buku_eksemplar e JOIN perpus_peminjaman_detail d ON d.eksemplar_id=e.id AND d.status='dipinjam' SET e.status='dipinjam'");
  $conn->query("UPDATE perpus_peminjaman p SET p.jumlah_item=(SELECT COUNT(*) FROM perpus_peminjaman_detail d WHERE d.peminjaman_id=p.id),p.status=IF(EXISTS(SELECT 1 FROM perpus_peminjaman_detail d2 WHERE d2.peminjaman_id=p.id AND d2.status='dipinjam'),'aktif','selesai')");

  if(perpusLegacyTableExists($legacy,'pengunjung')){$res=$legacy->query('SELECT * FROM pengunjung'.perpusLegacyCodeWhere($legacy,'pengunjung',$sourceCode).' ORDER BY id_pengunjung');$stmt=$conn->prepare("INSERT INTO perpus_kunjungan (legacy_id,anggota_id,waktu_kunjungan,sumber) VALUES (?,?,?,'migrasi') ON DUPLICATE KEY UPDATE anggota_id=VALUES(anggota_id),waktu_kunjungan=VALUES(waktu_kunjungan)");while($res&&($r=$res->fetch_assoc())){$legacyId=(int)$r['id_pengunjung'];$memberId=(int)($memberMap[(string)$r['ID_ANGGOTA']]??0);if($memberId<=0)continue;$date=perpusLegacyDate($r['tanggal_kunjungan'])?:date('Y-m-d');$date.=' 00:00:00';$stmt->bind_param('iis',$legacyId,$memberId,$date);$stmt->execute();$summary['kunjungan']++;}$stmt->close();}

  $summaryJson=json_encode($summary,JSON_UNESCAPED_UNICODE|JSON_PRETTY_PRINT);$stmt=$conn->prepare("UPDATE perpus_migrasi_log SET status='selesai',ringkasan=?,finished_at=NOW() WHERE id=?");$stmt->bind_param('si',$summaryJson,$logId);$stmt->execute();$stmt->close();$message='Migrasi selesai untuk ruang data lama '.($sourceCode!==''?$sourceCode:'default').'. Data telah dipindahkan ke tabel perpus_ dan identitas yang cocok terhubung ke master SDS.';
 }catch(Throwable $e){$error=$e->getMessage();if($logId>0){$stmt=$conn->prepare("UPDATE perpus_migrasi_log SET status='gagal',pesan_error=?,finished_at=NOW() WHERE id=?");$stmt->bind_param('si',$error,$logId);$stmt->execute();$stmt->close();}}
 finally{if($legacy instanceof mysqli)$legacy->close();}
